using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpServer.Tools;

[McpServerToolType]
public sealed class ApiFetchTool
{
    [McpServerTool, Description("Fetches data from an external API endpoint.")]
    public static async Task<string> FetchData(
        IHttpClientFactory httpClientFactory,
        [Description("The relative path to request (e.g. \"users/1\").")] string path,
        CancellationToken cancellationToken = default)
    {
        using var client = httpClientFactory.CreateClient("ExternalApi");

        var response = await client.GetAsync(path, cancellationToken);
        response.EnsureSuccessStatusCode();

        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

