using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpServer.Prompts;

[McpServerPromptType]
public sealed class SummarizePrompt
{
    [McpServerPrompt, Description("Generates a prompt that asks for a concise summary of the provided content.")]
    public static IEnumerable<ChatMessage> Summarize(
        [Description("The text content to summarize.")] string content,
        [Description("Optional maximum length hint (e.g. \"2 sentences\").")] string? maxLength = null)
    {
        var instruction = maxLength is not null
            ? $"Summarize the following content in {maxLength}:"
            : "Provide a concise summary of the following content:";

        return
        [
            new ChatMessage(ChatRole.User, $"{instruction}\n\n{content}")
        ];
    }
}

